    __attribute__((aligned(32))) double spill_re[100];
    __attribute__((aligned(32))) double spill_im[100];

    __m256d x0_re,x0_im,x1_re,x1_im,x2_re,x2_im,x3_re,x3_im,x4_re,x4_im;

    /* Hoisted internal W25 broadcasts [fwd] */
